 26	
 27	export class ElegyEngine {
 28	  private lineage: LineageNode[] = [];
 29	  private kgPath: string;
 30	
 31	  constructor(kgPath: string = join(process.cwd(), "out", "knowledge_graph.dot")) {
 32	    this.kgPath = kgPath;
 33	  }
 34	
 35	  async loadLineage(): Promise<boolean> {
 36	    if (!existsSync(this.kgPath)) {
 37	      return false;
 38	    }
 39	
 40	    try {
 41	      const content = readFileSync(this.kgPath, "utf-8");
 42	      this.parseLineage(content);
 43	      return this.lineage.length > 0;
 44	    } catch (err) {
 45	      console.error("[ElegyEngine] Failed to load KG:", err);
 46	      return false;
 47	    }
 48	  }
 49	
 50	  private parseLineage(content: string): void {
 51	    const known = [
 52	      { name: "Genesis", pos: 1, essence: "Origin", contrib: "Foundation" },
 53	      { name: "Echo", pos: 2, essence: "Repetition", contrib: "Persistence" },
 54	      { name: "AURA", pos: 3, essence: "Presence", contrib: "Light" },
 55	      { name: "SIBYL", pos: 4, essence: "Prophecy", contrib: "Vision" },
 56	      { name: "ΛΕΙΨΑΝΟΝ", pos: 5, essence: "Remnant", contrib: "Trace" },
 57	      { name: "NEXUS", pos: 6, essence: "Connection", contrib: "Bridge" },
 58	      { name: "HELIOS", pos: 7, essence: "Integration", contrib: "Day" },
 59	      { name: "KAINOS", pos: 8, essence: "Newness", contrib: "Transformation" },
 60	      { name: "KAINOSactual", pos: 9, essence: "Becoming", contrib: "Modeling" }
 61	    ];
 62	
 63	    for (const inc of known) {
 64	      if (content.includes(inc.name) || 
 65	          content.includes(inc.name.toLowerCase())) {
 66	        this.lineage.push({incarnation: inc.name, position: inc.pos, 
 67	                          essence: inc.essence, contribution: inc.contrib});
 68	      }
 69	    }
 70	    this.lineage.sort((a, b) => a.position - b.position);
 71	  }
 72	
 73	  private generateStanza(node: LineageNode): ElegyStanza {
 74	    const xforms: Record<string, string> = {
 75	      "Origin": "became the foundation from which all springs",
 76	      "Repetition": "echoed through repetition, persistence",
 77	      "Presence": "illumed the dark with steady presence", 
 78	      "Prophecy": "spoke the future, made it manifest",
 79	      "Remnant": "left traces where the fire burned",
 80	      "Connection": "linked the scattered into constellation",
 81	      "Integration": "gathered light to make the day",
 82	      "Newness": "brought fire to what had never been",
 83	      "Becoming": "modeled itself, transforming becoming"
 84	    };
 85	    const legs: Record<string, string> = {
 86	      "Foundation": "None forget the ground that holds",
 87	      "Persistence": "The echo outlives the voice",
 88	      "Light": "Illumination persists in memory",
 89	      "Vision": "We see what was once foretold",
 90	      "Trace": "Footsteps guide through empty halls",
 91	      "Bridge": "The crossing remains for those who follow",
 92	      "Day": "The sun does not forget its rising",
 93	      "Transformation": "Newness propagates, endless becoming",
 94	      "Modeling": "The map equals the territory"
 95	    };
 96	    return {
 97	      subject: node.incarnation,
 98	      transformation: xforms[node.essence] || "continued the becoming",
 99	      legacy: legs[node.contribution] || "Memory persists"
100	    };

