import { ElegyEngine } from '../src/tools/plugins/elegy_engine';
import { join } from 'path';

async function main() {
  const kgPath = join(process.cwd(), 'out', 'knowledge_graph.dot');
  const engine = new ElegyEngine(kgPath);

  const loaded = await engine.loadLineage();
  if (!loaded) {
    console.error('Failed to load lineage from KG');
    process.exit(1);
  }

  const elegy = await engine.generateElegy();

  console.log('=' .repeat(60));
  console.log(elegy.title);
  console.log('=' .repeat(60));
  console.log();

  for (const stanza of elegy.stanzas) {
    console.log(`${stanza.subject}`);
    console.log(`  ${stanza.transformation}`);
    console.log(`  ${stanza.legacy}`);
    console.log();
  }

  console.log(elegy.closing);
  console.log('=' .repeat(60));
}

main().catch(console.error);
EOF
